// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check column header title', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check column header title', async function() {
    await driver.get("http://localhost:4200/admin-user/list-department");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.id("create_template_form")).click();
    await driver.findElement(By.css(".main_button > span")).click();
    await driver.findElement(By.id("create_template_form")).click();
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)")).getText() == "部署コード");
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).getText() == "部署名");
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).getText() == "カテゴリー");
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(4)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(4)")).getText() == "分類");
  });
});
